;line&#34;&gt;94&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;95&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;96&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;97&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;98&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;99&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;100&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;101&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;102&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;103&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;104&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;105&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;106&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;107&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;108&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;109&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;110&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;111&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;112&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;113&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;114&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;115&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;116&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;117&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;118&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;119&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;120&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;121&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;122&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;123&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;124&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;125&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;126&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;127&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;128&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;129&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;130&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;131&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;132&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;133&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;134&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;135&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;136&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;137&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;138&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;139&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;140&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;141&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;142&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;143&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;144&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;145&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;146&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;147&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;148&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;149&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;150&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;151&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;152&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;153&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs pgsql&#34;&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#user  nobody;&lt;/span&gt;&lt;br&gt;worker_processes  &lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;;&lt;br&gt;&lt;br&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#error_log  logs/error.log;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#error_log  logs/error.log  notice;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#error_log  logs/error.log  info;&lt;/span&gt;&lt;br&gt;&lt;br&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#pid        logs/nginx.pid;&lt;/span&gt;&lt;br&gt;&lt;br&gt;&lt;br&gt;events &amp;#123;&lt;br&gt;    worker_connections  &lt;span class=&#34;hljs-number&#34;&gt;1024&lt;/span&gt;;&lt;br&gt;&amp;#125;&lt;br&gt;&lt;br&gt;&lt;br&gt;http &amp;#123;&lt;br&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt;       mime.&lt;span class=&#34;hljs-keyword&#34;&gt;types&lt;/span&gt;;&lt;br&gt;    default_type  application/octet-stream;&lt;br&gt;&lt;br&gt;    log_format  main  &lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;$remote_addr - $remote_user [$time_local] &amp;quot;$request&amp;quot; &amp;#x27;&lt;/span&gt;&lt;br&gt;                      &lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;$status $body_bytes_sent &amp;quot;$http_referer&amp;quot; &amp;#x27;&lt;/span&gt;&lt;br&gt;                      &lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;&amp;quot;$http_user_agent&amp;quot; &amp;quot;$http_x_forwarded_for&amp;quot;&amp;#x27;&lt;/span&gt;;&lt;br&gt;&lt;br&gt;    access_log  logs/&lt;span class=&#34;hljs-keyword&#34;&gt;access&lt;/span&gt;.&lt;span class=&#34;hljs-keyword&#34;&gt;log&lt;/span&gt;  main;&lt;br&gt;&lt;br&gt;    sendfile        &lt;span class=&#34;hljs-keyword&#34;&gt;on&lt;/span&gt;;&lt;br&gt;    tcp_nopush     &lt;span class=&#34;hljs-keyword&#34;&gt;on&lt;/span&gt;;&lt;br&gt;&lt;br&gt;    #keepalive_timeout  &lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;;&lt;br&gt;    keepalive_timeout  &lt;span class=&#34;hljs-number&#34;&gt;65&lt;/span&gt;;&lt;br&gt;&lt;br&gt;    gzip  &lt;span class=&#34;hljs-keyword&#34;&gt;on&lt;/span&gt;;&lt;br&gt;&lt;br&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;server&lt;/span&gt; &amp;#123;&lt;br&gt;        &lt;span class=&#34;hljs-keyword&#34;&gt;listen&lt;/span&gt;       &lt;span class=&#34;hljs-number&#34;&gt;80&lt;/span&gt;;&lt;br&gt;        server_name  localhost;&lt;br&gt;        &lt;br&gt;        #charset koi8-r;&lt;br&gt;&lt;br&gt;        access_log  logs/host.&lt;span class=&#34;hljs-keyword&#34;&gt;access&lt;/span&gt;.&lt;span class=&#34;hljs-keyword&#34;&gt;log&lt;/span&gt;  main;&lt;br&gt;&lt;br&gt;        &lt;span class=&#34;hljs-keyword&#34;&gt;location&lt;/span&gt; / &amp;#123;&lt;br&gt;            root   html;&lt;br&gt;            &lt;span class=&#34;hljs-keyword&#34;&gt;index&lt;/span&gt;  &lt;span class=&#34;hljs-keyword&#34;&gt;index&lt;/span&gt;.html &lt;span class=&#34;hljs-keyword&#34;&gt;index&lt;/span&gt;.htm;&lt;br&gt;        &amp;#125;&lt;br&gt;&lt;br&gt;        error_page  &lt;span class=&#34;hljs-number&#34;&gt;404&lt;/span&gt;              /&lt;span class=&#34;hljs-number&#34;&gt;404.&lt;/span&gt;html;&lt;br&gt;&lt;br&gt;        # redirect &lt;span class=&#34;hljs-keyword&#34;&gt;server&lt;/span&gt; error pages &lt;span class=&#34;hljs-keyword&#34;&gt;to&lt;/span&gt; the static page /&lt;span class=&#34;hljs-number&#34;&gt;50&lt;/span&gt;x.html&lt;br&gt;        #&lt;br&gt;       error_page   &lt;span class=&#34;hljs-number&#34;&gt;500&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;502&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;503&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;504&lt;/span&gt;  /&lt;span class=&#34;hljs-number&#34;&gt;50&lt;/span&gt;x.html;&lt;br&gt;        &lt;span class=&#34;hljs-keyword&#34;&gt;location&lt;/span&gt; = /&lt;span class=&#34;hljs-number&#34;&gt;50&lt;/span&gt;x.html &amp;#123;&lt;br&gt;            root   html;&lt;br&gt;        &amp;#125;&lt;br&gt;&lt;br&gt;        # proxy the PHP scripts &lt;span class=&#34;hljs-keyword&#34;&gt;to&lt;/span&gt; Apache listening &lt;span class=&#34;hljs-keyword&#34;&gt;on&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;127.0&lt;/span&gt;&lt;span class=&#34;hljs-number&#34;&gt;.0&lt;/span&gt;&lt;span class=&#34;hljs-number&#34;&gt;.1&lt;/span&gt;:&lt;span class=&#34;hljs-number&#34;&gt;80&lt;/span&gt;&lt;br&gt;        #&lt;br&gt;        &lt;span class=&#34;hljs-keyword&#34;&gt;location&lt;/span&gt; ~ \.php$ &amp;#123;&lt;br&gt;            proxy_pass   http://&lt;span class=&#34;hljs-number&#34;&gt;127.0&lt;/span&gt;&lt;span class=&#34;hljs-number&#34;&gt;.0&lt;/span&gt;&lt;span class=&#34;hljs-number&#34;&gt;.1&lt;/span&gt;;&lt;br&gt;        &amp;#125;&lt;br&gt;&lt;br&gt;        # pass the PHP scripts &lt;span class=&#34;hljs-keyword&#34;&gt;to&lt;/span&gt; FastCGI &lt;span class=&#34;hljs-keyword&#34;&gt;server&lt;/span&gt; listening &lt;span class=&#34;hljs-keyword&#34;&gt;on&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;127.0&lt;/span&gt;&lt;span class=&#34;hljs-number&#34;&gt;.0&lt;/span&gt;&lt;span class=&#34;hljs-number&#34;&gt;.1&lt;/span&gt;:&lt;span class=&#34;hljs-number&#34;&gt;9000&lt;/span&gt;&lt;br&gt;        #&lt;br&gt;        &lt;span class=&#34;hljs-keyword&#34;&gt;location&lt;/span&gt; ~ \.php$ &amp;#123;&lt;br&gt;            root           html;&lt;br&gt;            fastcgi_pass   &lt;span class=&#34;hljs-number&#34;&gt;127.0&lt;/span&gt;&lt;span class=&#34;hljs-number&#34;&gt;.0&lt;/span&gt;&lt;span class=&#34;hljs-number&#34;&gt;.1&lt;/span&gt;:&lt;span class=&#34;hljs-number&#34;&gt;9000&lt;/span&gt;;&lt;br&gt;            fastcgi_index  &lt;span class=&#34;hljs-keyword&#34;&gt;index&lt;/span&gt;.php;&lt;br&gt;            fastcgi_param  SCRIPT_FILENAME  /scripts$fastcgi_script_name;&lt;br&gt;            &lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt;        fastcgi_params;&lt;br&gt;        &amp;#125;&lt;br&gt;&lt;br&gt;        # deny &lt;span class=&#34;hljs-keyword&#34;&gt;access&lt;/span&gt; &lt;span class=&#34;hljs-keyword&#34;&gt;to&lt;/span&gt; .htaccess files, &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; Apach&lt;span class=&#34;hljs-string&#34;&gt;e&amp;#x27;s document root&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-string&#34;&gt;        # concurs with nginx&amp;#x27;&lt;/span&gt;s one&lt;br&gt;        #&lt;br&gt;        &lt;span class=&#34;hljs-keyword&#34;&gt;location&lt;/span&gt; ~ /\.ht &amp;#123;&lt;br&gt;            deny  &lt;span class=&#34;hljs-keyword&#34;&gt;all&lt;/span&gt;;&lt;br&gt;        &amp;#125;&lt;br&gt;    &amp;#125;&lt;br&gt;&lt;br&gt;&lt;br&gt;    # another virtual host &lt;span class=&#34;hljs-keyword&#34;&gt;using&lt;/span&gt; mix &lt;span class=&#34;hljs-keyword&#34;&gt;of&lt;/span&gt; IP-, &lt;span class=&#34;hljs-type&#34;&gt;name&lt;/span&gt;-, &lt;span class=&#34;hljs-keyword&#34;&gt;and&lt;/span&gt; port-based &lt;span class=&#34;hljs-keyword&#34;&gt;configuration&lt;/span&gt;&lt;br&gt;    #&lt;br&gt;    #&lt;span class=&#34;hljs-keyword&#34;&gt;server&lt;/span&gt; &amp;#123;&lt;br&gt;    #    &lt;span class=&#34;hljs-keyword&#34;&gt;listen&lt;/span&gt;       &lt;span class=&#34;hljs-number&#34;&gt;8000&lt;/span&gt;;&lt;br&gt;    #    &lt;span class=&#34;hljs-keyword&#34;&gt;listen&lt;/span&gt;       somename:&lt;span class=&#34;hljs-number&#34;&gt;8080&lt;/span&gt;;&lt;br&gt;    #    server_name  somename  &lt;span class=&#34;hljs-keyword&#34;&gt;alias&lt;/span&gt;  another.&lt;span class=&#34;hljs-keyword&#34;&gt;alias&lt;/span&gt;;&lt;br&gt;&lt;br&gt;    #    &lt;span class=&#34;hljs-keyword&#34;&gt;location&lt;/span&gt; / &amp;#123;&lt;br&gt;    #        root   html;&lt;br&gt;    #        &lt;span class=&#34;hljs-keyword&#34;&gt;index&lt;/span&gt;  &lt;span class=&#34;hljs-keyword&#34;&gt;index&lt;/span&gt;.html &lt;span class=&#34;hljs-keyword&#34;&gt;index&lt;/span&gt;.htm;&lt;br&gt;    #    &amp;#125;&lt;br&gt;    #&amp;#125;&lt;br&gt;&lt;br&gt;      &lt;span class=&#34;hljs-keyword&#34;&gt;server&lt;/span&gt;&amp;#123;&lt;br&gt;          &lt;span class=&#34;hljs-keyword&#34;&gt;listen&lt;/span&gt;    &lt;span class=&#34;hljs-number&#34;&gt;81&lt;/span&gt;;&lt;br&gt;          server_name webdav;&lt;br&gt;          error_log /etc/nginx/logs/webdav.error.&lt;span class=&#34;hljs-keyword&#34;&gt;log&lt;/span&gt; error;&lt;br&gt;          access_log  /etc/nginx/logs/webdav.&lt;span class=&#34;hljs-keyword&#34;&gt;access&lt;/span&gt;.&lt;span class=&#34;hljs-keyword&#34;&gt;log&lt;/span&gt; combined;&lt;br&gt;       &lt;span class=&#34;hljs-keyword&#34;&gt;location&lt;/span&gt; / &amp;#123;&lt;br&gt;             root /home/yk/www/nginx/webdav;&lt;br&gt;             charset utf&lt;span class=&#34;hljs-number&#34;&gt;-8&lt;/span&gt;;&lt;br&gt;             autoindex &lt;span class=&#34;hljs-keyword&#34;&gt;on&lt;/span&gt;;&lt;br&gt;             dav_methods  PUT &lt;span class=&#34;hljs-keyword&#34;&gt;DELETE&lt;/span&gt; MKCOL &lt;span class=&#34;hljs-keyword&#34;&gt;COPY&lt;/span&gt; &lt;span class=&#34;hljs-keyword&#34;&gt;MOVE&lt;/span&gt;;&lt;br&gt;             dav_ext_methods PROPFIND &lt;span class=&#34;hljs-keyword&#34;&gt;OPTIONS&lt;/span&gt;;&lt;br&gt;             create_full_put_path &lt;span class=&#34;hljs-keyword&#34;&gt;on&lt;/span&gt;;&lt;br&gt;             dav_access &lt;span class=&#34;hljs-keyword&#34;&gt;user&lt;/span&gt;:rw &lt;span class=&#34;hljs-keyword&#34;&gt;group&lt;/span&gt;:r &lt;span class=&#34;hljs-keyword&#34;&gt;all&lt;/span&gt;:r;&lt;br&gt;             auth_basic &amp;quot;Authorized Users Only&amp;quot;;&lt;br&gt;             auth_basic_user_file /etc/nginx/.htpasswd;&lt;br&gt;             client_max_body_size &lt;span class=&#34;hljs-number&#34;&gt;5&lt;/span&gt;G;&lt;br&gt;                &amp;#125;&lt;br&gt;           error_page   &lt;span class=&#34;hljs-number&#34;&gt;500&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;502&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;503&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;504&lt;/span&gt;  /&lt;span class=&#34;hljs-number&#34;&gt;50&lt;/span&gt;x.html;&lt;br&gt;           &lt;span class=&#34;hljs-keyword&#34;&gt;location&lt;/span&gt; = /&lt;span class=&#34;hljs-number&#34;&gt;50&lt;/span&gt;x.html &amp;#123;&lt;br&gt;               root   /etc/nginx/html;&lt;br&gt;             &amp;#125;&lt;br&gt;        &amp;#125;&lt;br&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;server&lt;/span&gt; &amp;#123;&lt;br&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;listen&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;8080&lt;/span&gt;;&lt;br&gt;    error_log /etc/nginx/logs/jianguoyun.error.&lt;span class=&#34;hljs-keyword&#34;&gt;log&lt;/span&gt; error;&lt;br&gt;    access_log  /etc/nginx/logs/jianguoyun.&lt;span class=&#34;hljs-keyword&#34;&gt;access&lt;/span&gt;.&lt;span class=&#34;hljs-keyword&#34;&gt;log&lt;/span&gt; combined;&lt;br&gt; &lt;br&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;location&lt;/span&gt; / &amp;#123;&lt;br&gt;        root /home/yk/www/nginx/jianguoyun;&lt;br&gt;        autoindex &lt;span class=&#34;hljs-keyword&#34;&gt;on&lt;/span&gt;;&lt;br&gt;        dav_methods PUT &lt;span class=&#34;hljs-keyword&#34;&gt;DELETE&lt;/span&gt; MKCOL &lt;span class=&#34;hljs-keyword&#34;&gt;COPY&lt;/span&gt; &lt;span class=&#34;hljs-keyword&#34;&gt;MOVE&lt;/span&gt;;&lt;br&gt;        dav_ext_methods PROPFIND &lt;span class=&#34;hljs-keyword&#34;&gt;OPTIONS&lt;/span&gt;;&lt;br&gt;        create_full_put_path &lt;span class=&#34;hljs-keyword&#34;&gt;on&lt;/span&gt;;&lt;br&gt;        dav_access &lt;span class=&#34;hljs-keyword&#34;&gt;user&lt;/span&gt;:rw &lt;span class=&#34;hljs-keyword&#34;&gt;group&lt;/span&gt;:r &lt;span class=&#34;hljs-keyword&#34;&gt;all&lt;/span&gt;:r;&lt;br&gt;        auth_basic &amp;quot;Authorized Users Only&amp;quot;;&lt;br&gt;        auth_basic_user_file /etc/nginx/.htpasswd;&lt;br&gt;    &amp;#125;&lt;br&gt;&amp;#125;&lt;br&gt;    # HTTPS &lt;span class=&#34;hljs-keyword&#34;&gt;server&lt;/span&gt;&lt;br&gt;    #&lt;br&gt;    #&lt;span class=&#34;hljs-keyword&#34;&gt;server&lt;/span&gt; &amp;#123;&lt;br&gt;    #    &lt;span class=&#34;hljs-keyword&#34;&gt;listen&lt;/span&gt;       &lt;span class=&#34;hljs-number&#34;&gt;443&lt;/span&gt; ssl;&lt;br&gt;    #    server_name  localhost;&lt;br&gt;&lt;br&gt;    #    ssl_certificate      cert.pem;&lt;br&gt;    #    ssl_certificate_key  cert.key;&lt;br&gt;&lt;br&gt;    #    ssl_session_cache    shared:SSL:&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;m;&lt;br&gt;    #    ssl_session_timeout  &lt;span class=&#34;hljs-number&#34;&gt;5&lt;/span&gt;m;&lt;br&gt;&lt;br&gt;    #    ssl_ciphers  HIGH:!aNULL:!MD5;&lt;br&gt;    #    ssl_prefer_server_ciphers  &lt;span class=&#34;hljs-keyword&#34;&gt;on&lt;/span&gt;;&lt;br&gt;&lt;br&gt;    #    &lt;span class=&#34;hljs-keyword&#34;&gt;location&lt;/span&gt; / &amp;#123;&lt;br&gt;    #        root   html;&lt;br&gt;    #        &lt;span class=&#34;hljs-keyword&#34;&gt;index&lt;/span&gt;  &lt;span class=&#34;hljs-keyword&#34;&gt;index&lt;/span&gt;.html &lt;span class=&#34;hljs-keyword&#34;&gt;index&lt;/span&gt;.htm;&lt;br&gt;    #    &amp;#125;&lt;br&gt;    #&amp;#125;&lt;br&gt;&lt;br&gt;&amp;#125;&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h3 id=&#34;（2）设置webdav帐号和密码：&#34;&gt;&lt;a href=&#34;#（2）设置webdav帐号和密码：&#34; class=&#34;headerlink&#34; title=&#34;（2）设置webdav帐号和密码：&#34;&gt;&lt;/a&gt;（2）设置webdav帐号和密码：&lt;/h3&gt;&lt;figure class=&#34;highlight awk&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs awk&#34;&gt;root@yk-pc:&lt;span class=&#34;hljs-regexp&#34;&gt;/etc/&lt;/span&gt;nginx&lt;span class=&#34;hljs-comment&#34;&gt;# echo -n &amp;#x27;yk:&amp;#x27; | tee /etc/nginx/.htpasswd&lt;/span&gt;&lt;br&gt;yk:root@yk-pc:&lt;span class=&#34;hljs-regexp&#34;&gt;/etc/&lt;/span&gt;nginx&lt;span class=&#34;hljs-comment&#34;&gt;# openssl passwd -apr1 | tee -a /etc/nginx/.htpasswd&lt;/span&gt;&lt;br&gt;Password: &lt;br&gt;Verifying - Password: &lt;br&gt;&lt;span class=&#34;hljs-variable&#34;&gt;$apr1&lt;/span&gt;&lt;span class=&#34;hljs-variable&#34;&gt;$6aLRK&lt;/span&gt;.&lt;span class=&#34;hljs-number&#34;&gt;3&lt;/span&gt;F&lt;span class=&#34;hljs-variable&#34;&gt;$gg76W8E9vT65vn1cE&lt;/span&gt;/Mk41&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;（3）挂载到坚果云方法&#34;&gt;&lt;a href=&#34;#（3）挂载到坚果云方法&#34; class=&#34;headerlink&#34; title=&#34;（3）挂载到坚果云方法&#34;&gt;&lt;/a&gt;（3）挂载到坚果云方法&lt;/h3&gt;&lt;figure class=&#34;highlight awk&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs awk&#34;&gt;yk@yk-pc:~$ sudo apt-get install davfs2&lt;br&gt;yk@yk-pc:~$ mkdir -p &lt;span class=&#34;hljs-regexp&#34;&gt;/home/y&lt;/span&gt;k&lt;span class=&#34;hljs-regexp&#34;&gt;/www/&lt;/span&gt;nginx/jianguoyun&lt;br&gt;yk@yk-pc:~$ sudo vim  &lt;span class=&#34;hljs-regexp&#34;&gt;/etc/&lt;/span&gt;davfs2/davfs2.conf&lt;br&gt;&lt;span class=&#34;hljs-comment&#34;&gt;#ignore_dav_header 0&lt;/span&gt;&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;  改为：&lt;br&gt;&lt;code&gt;ignore_dav_header 1&lt;/code&gt;&lt;br&gt;  挂载：&lt;br&gt;&lt;code&gt;yk@yk-pc:~$ sudo mount -t davfs https://dav.jianguoyun.com/dav/ /home/yk/www/nginx/jianguoyun&lt;/code&gt;&lt;br&gt;取消挂载：&lt;br&gt;&lt;code&gt;yk@yk-pc:~$ sudo fusermount -u /home/yk/www/nginx/jianguoyun&lt;/code&gt;&lt;/p&gt;
&lt;h3 id=&#34;（4）nginx加入到systemctl服务运行&#34;&gt;&lt;a href=&#34;#（4）nginx加入到systemctl服务运行&#34; class=&#34;headerlink&#34; title=&#34;（4）nginx加入到systemctl服务运行&#34;&gt;&lt;/a&gt;（4）&lt;code&gt;nginx&lt;/code&gt;加入到&lt;code&gt;systemctl&lt;/code&gt;服务运行&lt;/h3&gt;&lt;p&gt;  &lt;code&gt;yk@yk-pc:~$ sudo vim /usr/lib/systemd/system/nginx.service&lt;/code&gt;&lt;br&gt;输入以下内容并保存&lt;br&gt;&lt;figure class=&#34;highlight ini&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs ini&#34;&gt;&lt;span class=&#34;hljs-section&#34;&gt;[Unit]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-attr&#34;&gt;Description&lt;/span&gt;=nginx&lt;br&gt;&lt;span class=&#34;hljs-attr&#34;&gt;After&lt;/span&gt;=network.target&lt;br&gt;&lt;span class=&#34;hljs-section&#34;&gt;[Service]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-attr&#34;&gt;Type&lt;/span&gt;=forking&lt;br&gt;&lt;span class=&#34;hljs-attr&#34;&gt;PIDFile&lt;/span&gt;=/etc/nginx/logs/nginx.pid&lt;br&gt;&lt;span class=&#34;hljs-attr&#34;&gt;ExecStart&lt;/span&gt;=/etc/nginx/sbin/nginx&lt;br&gt;&lt;span class=&#34;hljs-attr&#34;&gt;ExecReload&lt;/span&gt;=/etc/nginx/sbin/nginx -s reload&lt;br&gt;&lt;span class=&#34;hljs-attr&#34;&gt;ExecStop&lt;/span&gt;=/etc/nginx/sbin/nginx -s stop&lt;br&gt;&lt;span class=&#34;hljs-attr&#34;&gt;PrivateTmp&lt;/span&gt;=&lt;span class=&#34;hljs-literal&#34;&gt;true&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-section&#34;&gt;[Install]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-attr&#34;&gt;WantedBy&lt;/span&gt;=multi-user.target&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h3 id=&#34;（5）常用命令：&#34;&gt;&lt;a href=&#34;#（5）常用命令：&#34; class=&#34;headerlink&#34; title=&#34;（5）常用命令：&#34;&gt;&lt;/a&gt;（5）常用命令：&lt;/h3&gt;&lt;figure class=&#34;highlight elixir&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs elixir&#34;&gt;yk&lt;span class=&#34;hljs-variable&#34;&gt;@yk&lt;/span&gt;-&lt;span class=&#34;hljs-symbol&#34;&gt;pc:&lt;/span&gt;~&lt;span class=&#34;hljs-variable&#34;&gt;$ &lt;/span&gt;systemctl daemon-reload&lt;br&gt;yk&lt;span class=&#34;hljs-variable&#34;&gt;@yk&lt;/span&gt;-&lt;span class=&#34;hljs-symbol&#34;&gt;pc:&lt;/span&gt;~&lt;span class=&#34;hljs-variable&#34;&gt;$ &lt;/span&gt;systemctl start/stop/reload nginx&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;四、手机用的连接为webdav软件：-1&#34;&gt;&lt;a href=&#34;#四、手机用的连接为webdav软件：-1&#34; class=&#34;headerlink&#34; title=&#34;四、手机用的连接为webdav软件：&#34;&gt;&lt;/a&gt;四、手机用的连接为webdav软件：&lt;/h2&gt;&lt;p&gt;   &lt;strong&gt;苹果：FE文件管理器、ES文件浏览器&lt;/strong&gt;&lt;br&gt;   &lt;strong&gt;安卓：CX文件管理器、ES文件浏览器&lt;/strong&gt;&lt;/p&gt;
&lt;h2 id=&#34;五、一些问题及解决方法：&#34;&gt;&lt;a href=&#34;#五、一些问题及解决方法：&#34; class=&#34;headerlink&#34; title=&#34;五、一些问题及解决方法：&#34;&gt;&lt;/a&gt;五、一些问题及解决方法：&lt;/h2&gt;&lt;h3 id=&#34;1-查找进程：&#34;&gt;&lt;a href=&#34;#1-查找进程：&#34; class=&#34;headerlink&#34; title=&#34;1. 查找进程：&#34;&gt;&lt;/a&gt;1. 查找进程：&lt;/h3&gt;&lt;p&gt;  查询端口：&lt;br&gt;  &lt;code&gt;ps -ef |grep nginx&lt;/code&gt;&lt;/p&gt;
&lt;h3 id=&#34;2-开放端口：&#34;&gt;&lt;a href=&#34;#2-开放端口：&#34; class=&#34;headerlink&#34; title=&#34;2. 开放端口：&#34;&gt;&lt;/a&gt;2. 开放端口：&lt;/h3&gt;&lt;figure class=&#34;highlight typescript&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs typescript&#34;&gt;yk&lt;span class=&#34;hljs-meta&#34;&gt;@yk&lt;/span&gt;-pc:&lt;span class=&#34;hljs-regexp&#34;&gt;/etc/&lt;/span&gt;nginx/logs$ sudo apt-get install iptables&lt;br&gt;yk&lt;span class=&#34;hljs-meta&#34;&gt;@yk&lt;/span&gt;-pc:&lt;span class=&#34;hljs-regexp&#34;&gt;/etc/&lt;/span&gt;nginx/logs$ sudo ln -s /usr/sbin/iptables /usr/bin/iptables  &lt;span class=&#34;hljs-comment&#34;&gt;//建立软连接&lt;/span&gt;&lt;br&gt;yk&lt;span class=&#34;hljs-meta&#34;&gt;@yk&lt;/span&gt;-pc:&lt;span class=&#34;hljs-regexp&#34;&gt;/etc/&lt;/span&gt;nginx/logs$ sudo iptables -I INPUT -p tcp --dport &lt;span class=&#34;hljs-number&#34;&gt;81&lt;/span&gt; -j ACCEPT  &lt;span class=&#34;hljs-comment&#34;&gt;//开放81端口&lt;/span&gt;&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;持久化规则：这里我们需要在安装一下工具来帮我们实现，这里我们使用 &lt;code&gt;iptables-persistent&lt;/code&gt;&lt;br&gt;安装&lt;code&gt;iptables-persistent&lt;/code&gt;&lt;br&gt;  &lt;code&gt;yk@yk-pc:/etc/nginx/logs$ sudo apt-get install iptables-persistent&lt;/code&gt;&lt;br&gt;持久化规则&lt;br&gt;&lt;figure class=&#34;highlight typescript&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs typescript&#34;&gt;yk&lt;span class=&#34;hljs-meta&#34;&gt;@yk&lt;/span&gt;-pc:&lt;span class=&#34;hljs-regexp&#34;&gt;/etc/&lt;/span&gt;nginx/logs$ sudo netfilter-persistent save&lt;br&gt;yk&lt;span class=&#34;hljs-meta&#34;&gt;@yk&lt;/span&gt;-pc:&lt;span class=&#34;hljs-regexp&#34;&gt;/etc/&lt;/span&gt;nginx/logs$ sudo netfilter-persistent reload&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;完成上述操作就可以永久打开我们需要的端口了&lt;/p&gt;
&lt;h3 id=&#34;3-关于权限问题：&#34;&gt;&lt;a href=&#34;#3-关于权限问题：&#34; class=&#34;headerlink&#34; title=&#34;3. 关于权限问题：&#34;&gt;&lt;/a&gt;3. 关于权限问题：&lt;/h3&gt;&lt;figure class=&#34;highlight awk&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs awk&#34;&gt; yk@yk-pc:&lt;span class=&#34;hljs-regexp&#34;&gt;/etc/&lt;/span&gt;nginx/conf$ sudo vim nginx.conf&lt;br&gt; [sudo] yk 的密码：&lt;br&gt;&lt;span class=&#34;hljs-comment&#34;&gt;#user  nobody;&lt;/span&gt;&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;注释掉&lt;code&gt;user&lt;/code&gt;，改为&lt;br&gt;&lt;code&gt;user  nginx;&lt;/code&gt;&lt;br&gt;重新加载出现：错误提示如下：&lt;br&gt;&lt;figure class=&#34;highlight awk&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs awk&#34;&gt;yk@yk-pc:&lt;span class=&#34;hljs-regexp&#34;&gt;/etc/&lt;/span&gt;nginx/conf$ sudo nginx -s reload&lt;br&gt;nginx: [emerg] getpwnam(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;nginx&amp;quot;&lt;/span&gt;) failed &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;hljs-regexp&#34;&gt;/etc/&lt;/span&gt;nginx&lt;span class=&#34;hljs-regexp&#34;&gt;/conf/&lt;/span&gt;nginx.conf:&lt;span class=&#34;hljs-number&#34;&gt;2&lt;/span&gt;&lt;br&gt;yk@yk-pc:&lt;span class=&#34;hljs-regexp&#34;&gt;/etc/&lt;/span&gt;nginx/conf$ sudo nginx -s closed&lt;br&gt;nginx: invalid option: &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;-s closed&amp;quot;&lt;/span&gt;&lt;br&gt;yk@yk-pc:&lt;span class=&#34;hljs-regexp&#34;&gt;/etc/&lt;/span&gt;nginx/conf$ sudo nginx -s stop&lt;br&gt;nginx: [emerg] getpwnam(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;nginx&amp;quot;&lt;/span&gt;) failed &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;hljs-regexp&#34;&gt;/etc/&lt;/span&gt;nginx&lt;span class=&#34;hljs-regexp&#34;&gt;/conf/&lt;/span&gt;nginx.conf:&lt;span class=&#34;hljs-number&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;&lt;strong&gt;解决办法：&lt;/strong&gt;&lt;br&gt;&lt;figure class=&#34;highlight typescript&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs typescript&#34;&gt;yk&lt;span class=&#34;hljs-meta&#34;&gt;@yk&lt;/span&gt;-pc:&lt;span class=&#34;hljs-regexp&#34;&gt;/etc/&lt;/span&gt;nginx/conf$ sudo useradd -s /sbin/nologin -M  nginx&lt;br&gt;useradd：用户“nginx”已存在&lt;br&gt;yk&lt;span class=&#34;hljs-meta&#34;&gt;@yk&lt;/span&gt;-pc:&lt;span class=&#34;hljs-regexp&#34;&gt;/etc/&lt;/span&gt;nginx/conf$ id nginx&lt;br&gt;uid=&lt;span class=&#34;hljs-number&#34;&gt;117&lt;/span&gt;(nginx) gid=&lt;span class=&#34;hljs-number&#34;&gt;125&lt;/span&gt;(nginx) 组=&lt;span class=&#34;hljs-number&#34;&gt;125&lt;/span&gt;(nginx)&lt;br&gt;yk&lt;span class=&#34;hljs-meta&#34;&gt;@yk&lt;/span&gt;-pc:&lt;span class=&#34;hljs-regexp&#34;&gt;/etc/&lt;/span&gt;nginx/conf$ systemctl start nginx&lt;br&gt;yk&lt;span class=&#34;hljs-meta&#34;&gt;@yk&lt;/span&gt;-pc:&lt;span class=&#34;hljs-regexp&#34;&gt;/etc/&lt;/span&gt;nginx/conf$  sudo nginx -s reload&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h3 id=&#34;4-make-upgrade-平滑升级&#34;&gt;&lt;a href=&#34;#4-make-upgrade-平滑升级&#34; class=&#34;headerlink&#34; title=&#34;4. make upgrade 平滑升级&#34;&gt;&lt;/a&gt;4. &lt;code&gt;make upgrade&lt;/code&gt; 平滑升级&lt;/h3&gt;&lt;figure class=&#34;highlight awk&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs awk&#34;&gt;&lt;span class=&#34;hljs-regexp&#34;&gt;/sbin/m&lt;/span&gt;ount.davfs: mounting failed; the server does not support WebDAV&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;原因是&lt;code&gt;mount.davfs&lt;/code&gt;命令在挂载时和 &lt;code&gt;WebDAV&lt;/code&gt; 服务器建立连接，并通过 &lt;code&gt;libneon&lt;/code&gt;库的 &lt;code&gt;ne_options&lt;/code&gt; 函数发送 &lt;code&gt;HTTP OPTIONS&lt;/code&gt; 请求获取 &lt;code&gt;WebDAV&lt;/code&gt; 服务器能力，虽然返回成功但判断坚果云 &lt;code&gt;WebDAV&lt;/code&gt; 服务器不支持 &lt;code&gt;Class 1 WebDAV&lt;/code&gt;，因此直接报错挂载失败。&lt;br&gt;看到这里解决办法也就简单了，&lt;code&gt;davfs2&lt;/code&gt; 提供了通过配置文件禁用 &lt;code&gt;WebDAV&lt;/code&gt;头检测的功能，&lt;br&gt;&lt;figure class=&#34;highlight awk&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs awk&#34;&gt;直接修改 &lt;span class=&#34;hljs-regexp&#34;&gt;/etc/&lt;/span&gt;davfs2/davfs2.conf 配置文件解注释并改为：ignore_dav_header &lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h2 id=&#34;参考：&#34;&gt;&lt;a href=&#34;#参考：&#34; class=&#34;headerlink&#34; title=&#34;参考：&#34;&gt;&lt;/a&gt;参考：&lt;/h2&gt;&lt;ol&gt;
&lt;li&gt;&lt;a href=&#34;http://www.v5b7.com/webserver/nginx/nginx_webdav.html&#34;&gt;nginx配置webdav：&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;https://www.cnblogs.com/catlee/p/10290497.html&#34;&gt;源码编译安装nginx详细步骤：&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;https://xieshaohu.wordpress.com/2019/07/12/nginx%E7%BC%96%E8%AF%91%E5%AE%89%E8%A3%85webdav%E6%A8%A1%E5%9D%97/&#34;&gt;nginx编译安装webdav模块：&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;https://blog.ghostry.cn/server/889.html&#34;&gt;debian下为Nginx添加webdav:&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;https://blog.csdn.net/u013401853/article/details/113094734&#34;&gt;davfs挂载与使用缺陷：&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;https://www.moerats.com/archives/317/&#34;&gt;Linux通过安装davfs2来挂载webdav网盘：&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;https://www.cnblogs.com/Dev0ps/p/12000221.html&#34;&gt;Nginx服务加到systemctl:&lt;/a&gt;&lt;/li&gt;
&lt;/ol&gt;
